// Unit 25. Si Hubiera Sabido
// Subjuntivo Imperfecto

export default {n:25,lang:"es",srcLang:"en",track:"v2",title:"Si Hubiera Sabido",sub:"Subjuntivo Imperfecto",icon:"🌊",level:"B2.1",color:"#7B5EE8",lessons:[
  {id:"esp25l1",title:"Si yo hablara...",icon:"🗣️",xp:25,board:true,steps:[
        {type:"intro",title:"Si yo hablara...",desc:"Welcome to the imperfect subjunctive. This powerful mood lets you express wishes, hypotheticals, and unreal conditions. We start with -AR verbs.",goals:["Form the imperfect subjunctive of -AR verbs","Recognize the -ara ending pattern","Use imperfect subjunctive in basic hypothetical sentences"]},
        {type:"tip",title:"What is the Imperfect Subjunctive?",text:"The imperfect subjunctive (subjuntivo imperfecto) expresses:\n\n1. Hypothetical or unreal situations\n2. Wishes about things that probably will not happen\n3. Past subjunctive contexts\n4. Polite requests (quisiera)\n\nTo form it, take the ellos form of the preterite, drop -ron, and add the new endings.",icon:"📖"},
        {type:"teach",trg:"hablara",src:"I spoke / I would speak (subj.)",pos:"noun",gender:null,phonetic:"ah-BLA-ra",note:"From hablar. Preterite ellos: hablaron. Drop -ron, add -ra.",example:"A: ¿Qué harías si hablaras cinco idiomas?\nB: Viajaría por todo el mundo sin preocuparme.\nA: Yo también. Empezaría por Asia.\nB: Si yo hablara japonés, iría a Tokio primero.\nA: Bueno, nunca es tarde para aprender.",exampleSrc:"A: What would you do if you spoke five languages?\nB: I would travel the world without worrying.\nA: Me too. I would start with Asia.\nB: If I spoke Japanese, I would go to Tokyo first.\nA: Well, it is never too late to learn.",funFact:"Imperfect subjunctive, yo form. -ar verb gets -ara. Spelled 'hablara' (no accent). Alt form: 'hablase' (interchangeable but less common in speech)."},
        {type:"teach",trg:"hablaras",src:"you spoke / you would speak (subj.)",pos:"noun",gender:null,phonetic:"ah-BLA-ras",note:"Tú form. Same stem as hablara, just add -s.",example:"A: Si hablaras con el jefe, ¿qué le dirías?\nB: Le pediría un aumento de sueldo.\nA: ¿Y si no te lo diera?\nB: Buscaría otro trabajo.\nA: Siempre es bueno tener un plan.",exampleSrc:"A: If you spoke with the boss, what would you say?\nB: I would ask him for a raise.\nA: And if he did not give it to you?\nB: I would look for another job.\nA: It is always good to have a plan.",funFact:"Tú form of imperfect subjunctive. 'Hablaras'; you would speak (hypothetical). Used after si-clauses: 'si hablaras español...'."},
        {type:"teach",trg:"habláramos",src:"we spoke / we would speak (subj.)",pos:"noun",gender:null,phonetic:"ah-BLA-ra-mos",note:"Nosotros form. Note the accent on the a before -ramos: habláramos.",example:"A: Ojalá habláramos más a menudo.\nB: Tienes razón. Siempre estamos ocupados.\nA: Si habláramos cada semana, no perderíamos el contacto.\nB: Podríamos hacer videollamadas los domingos.\nA: Me parece perfecto.",exampleSrc:"A: I wish we spoke more often.\nB: You are right. We are always busy.\nA: If we spoke every week, we would not lose touch.\nB: We could do video calls on Sundays.\nA: That sounds perfect to me.",funFact:"Nosotros form. Accent on á to preserve stress. The alternative -ásemos form exists (hablásemos). Latin American favors -ara; Spain uses both."},
        {type:"teach",trg:"hablaran",src:"they spoke / they would speak (subj.)",pos:"noun",gender:null,phonetic:"ah-BLA-ran",note:"Ellos/ellas/ustedes form. Same as yo form but with -n.",example:"A: El profesor quería que hablaran en español.\nB: Pero muchos estudiantes tenían miedo.\nA: Es normal al principio.\nB: Si hablaran más en clase, mejorarían rápido.\nA: Exacto. La práctica es la clave.",exampleSrc:"A: The teacher wanted them to speak in Spanish.\nB: But many students were afraid.\nA: That is normal at the beginning.\nB: If they spoke more in class, they would improve quickly.\nA: Exactly. Practice is the key.",funFact:"Ellos/ustedes. 'Hablaran'; they would speak. Note: one 'r,' not double. Contrast with 'hablarán' (future with accent on á)."},
        {type:"verb_table",title:"Hablar: Imperfect Subjunctive",note:"All -AR verbs follow this pattern. Stem from preterite ellos form.",groups:[{label:"Singular",items:["yo hablara","tú hablaras","él/ella hablara"],rows:[]},{label:"Plural",items:["nosotros habláramos","vosotros hablarais","ellos hablaran"],rows:[]}],label:"hablar (to speak)"},
        {type:"tip",title:"How to Build the Stem",text:"The recipe is simple:\n\n1. Take the verb in preterite ellos form: hablaron\n2. Remove -ron: habla-\n3. Add endings: -ra, -ras, -ra, -ramos, -rais, -ran\n\nThis works for ALL verbs, regular and irregular. The preterite ellos form is your key.",icon:"🔑"},
        {type:"mc",q:"The imperfect subjunctive of 'yo hablar' is:",opts:["hablara","hablé","hablo","hablaría"],ans:"hablara",hint:"This form ends in -ra and expresses hypotheticals."},
        {type:"mc",q:"To form the imperfect subjunctive stem, you start from:",opts:["The infinitive","The preterite ellos form","The present tense yo form","The future stem"],ans:"The preterite ellos form",hint:"You take a past tense ___ used with ___ and remove two letters."},
        {type:"fb",opts:["hablara","hablo","hablé","hablaría"],hint:"The hypothetical clause uses imperfect subjunctive, not indicative.",s:"Si yo {1} español, viviría en Madrid.",a:"hablara"},
        {type:"teach",trg:"trabajara",src:"I worked / I would work (subj.)",pos:"noun",gender:null,phonetic:"tra-ba-HA-ra",note:"From trabajar. Same -ara pattern: trabajaron > trabaja- > trabajara.",example:"A: Si trabajara menos horas, tendría más tiempo libre.\nB: Yo también pienso eso a veces.\nA: ¿Qué harías con más tiempo?\nB: Aprendería a tocar la guitarra.\nA: Si yo trabajara desde casa, ahorraría dos horas al día.",exampleSrc:"A: If I worked fewer hours, I would have more free time.\nB: I think that sometimes too.\nA: What would you do with more time?\nB: I would learn to play the guitar.\nA: If I worked from home, I would save two hours a day.",funFact:"-ar imperfect subjunctive. Yo form. 'Si trabajara más, ganaría más'; If I worked more, I would earn more. Core second-conditional structure."},
        {type:"teach",trg:"estudiara",src:"I studied / I would study (subj.)",pos:"noun",gender:null,phonetic:"es-too-DYA-ra",note:"From estudiar. Preterite: estudiaron > estudia- > estudiara.",example:"A: Si estudiara medicina, mis padres estarían muy contentos.\nB: ¿Y tú? ¿Estarías contento?\nA: No lo sé. Me gusta más el arte.\nB: Si estudiaras arte, ¿de qué vivirías?\nA: Buena pregunta. Por eso estudio ingeniería.",exampleSrc:"A: If I studied medicine, my parents would be very happy.\nB: And you? Would you be happy?\nA: I do not know. I like art more.\nB: If you studied art, what would you live from?\nA: Good question. That is why I study engineering.",funFact:"Yo form. 'Quería que estudiara'; he wanted me to study (past). Used when the main verb is past and triggers subjunctive."},
        {type:"mc",q:"'Si ella cantara en el concierto' means:",opts:["She sings at the concert","She sang at the concert","If she sang at the concert","She will sing at the concert"],ans:"If she sang at the concert",hint:"The si + imperfect subjunctive pattern expresses something hypothetical."},
        {type:"fb",opts:["estudiáramos","estudiamos","estudiaríamos","estudiemos"],hint:"The nosotros imperfect subjunctive of estudiar, with an accent mark.",s:"Si nosotros {1} más, aprobaríamos el examen.",a:"estudiáramos"},
        {type:"mc",q:"Which sentence uses the imperfect subjunctive correctly?",opts:["Si hablo español, viajo a México","Si hablando español, viajaría a México","Si hablaré español, viajo a México","Si hablara español, viajaría a México"],ans:"Si hablara español, viajaría a México",hint:"The pattern is si + imperfect subjunctive + conditional."},
        {type:"drag_fill",hint:"Hypothetical: si + subjunctive in the if-clause, conditional in the result.",s:"Si tú {1} en esta empresa, {2} más dinero.",blanks:{"1":"trabajaras","2":"ganarías"},pool:["trabajaras","ganarías","trabajas","ganas","trabajarías"]},
        {type:"match",pairs:[
          {trg:"hablara",src:"I spoke (subj.)"},
          {trg:"hablaras",src:"you spoke (subj.)"},
          {trg:"habláramos",src:"we spoke (subj.)"},
          {trg:"hablaran",src:"they spoke (subj.)"},
          {trg:"trabajara",src:"I worked (subj.)"}
        ]},
        {type:"mc",q:"'Si viajáramos a España, visitaríamos Barcelona.' What does viajáramos express?",opts:["A hypothetical trip that may not happen","A plan for next summer","A trip that already happened","A command to travel"],ans:"A hypothetical trip that may not happen",hint:"The imperfect subjunctive marks the situation as unreal or unlikely."}
  ]},
  {id:"esp25l2",title:"Si comiera, si viviera...",icon:"🍽️",xp:25,board:true,steps:[
        {type:"intro",title:"Si comiera, si viviera...",desc:"The imperfect subjunctive of -ER and -IR verbs uses the same endings as -AR verbs. The stem comes from the preterite ellos form, just like before.",goals:["Form the imperfect subjunctive of -ER/-IR verbs","Recognize that -ER and -IR share identical endings","Use these forms in hypothetical sentences"]},
        {type:"teach",trg:"comiera",src:"I ate / I would eat (subj.)",pos:"noun",gender:null,phonetic:"ko-MYE-ra",note:"From comer. Preterite ellos: comieron. Drop -ron: comie-. Add -ra.",example:"A: Si comiera menos dulces, perdería peso.\nB: Eso dicen todos, pero es difícil.\nA: Si no comiera chocolate, estaría triste.\nB: Yo también. La vida sin chocolate no tiene sentido.\nA: Entonces comamos chocolate y seamos felices.",exampleSrc:"A: If I ate fewer sweets, I would lose weight.\nB: Everyone says that, but it is hard.\nA: If I did not eat chocolate, I would be sad.\nB: Me too. Life without chocolate makes no sense.\nA: Then let us eat chocolate and be happy.",funFact:"-er verb imperfect subjunctive. Yo/él/ella share this form. 'Si comiera menos...'; if I ate less. Alt: comiese."},
        {type:"teach",trg:"viviera",src:"I lived / I would live (subj.)",pos:"noun",gender:null,phonetic:"bee-BYE-ra",note:"From vivir. Preterite ellos: vivieron. Drop -ron: vivie-. Add -ra.",example:"A: Si viviera en la playa, estaría muy contento.\nB: ¿En qué playa vivirías?\nA: En alguna isla del Caribe.\nB: Si yo viviera allí, estaría muy feliz.\nA: Sí, sería perfecto.",exampleSrc:"A: If I lived at the beach, I would be very happy.\nB: At which beach would you live?\nA: On some Caribbean island.\nB: If I lived there, I would be very happy.\nA: Yes, it would be perfect.",funFact:"-ir verb same endings as -er in subjunctive. 'Si viviera en Madrid, hablaría español todos los días.' Classic hypothetical statement."},
        {type:"tip",title:"-ER and -IR: Same Endings",text:"-ER and -IR verbs share identical imperfect subjunctive forms:\n\ncomer > comieron > comie- > comiera\nvivir > vivieron > vivie- > viviera\n\nThe endings are the same as -AR verbs:\n-ra, -ras, -ra, -ramos, -rais, -ran\n\nOnly the stem vowel changes (ie instead of a).",icon:"💡"},
        {type:"verb_table",title:"Comer / Vivir: Imperfect Subjunctive",note:"-ER and -IR verbs have identical endings in the imperfect subjunctive.",groups:[
          {label:"comer",items:["yo comiera","tú comieras","él comiera","nosotros comiéramos","ellos comieran"],rows:[]},
          {label:"vivir",items:["yo viviera","tú vivieras","él viviera","nosotros viviéramos","ellos vivieran"],rows:[]}
        ],label:"comer / vivir"},
        {type:"mc",q:"The imperfect subjunctive of 'yo comer' is:",opts:["comiera","comía","como","comería"],ans:"comiera",hint:"This form ends in -iera and is used in hypothetical clauses."},
        {type:"fb",opts:["viviera","vive","vivía","viviría"],hint:"The if-clause needs the imperfect subjunctive form of vivir.",s:"Si ella {1} aquí, todo sería diferente.",a:"viviera"},
        {type:"teach",trg:"escribiera",src:"I wrote / I would write (subj.)",pos:"noun",gender:null,phonetic:"es-kree-BYE-ra",note:"From escribir. Preterite: escribieron > escribie- > escribiera.",example:"A: Si escribiera un libro, ¿sobre qué sería?\nB: Escribiría sobre mis viajes por Sudamérica.\nA: ¡Qué interesante! Si yo escribiera uno, sería de ciencia ficción.\nB: ¿Y si escribiéramos uno juntos?\nA: Viajes intergalácticos por Sudamérica. Perfecto.",exampleSrc:"A: If you wrote a book, what would it be about?\nB: I would write about my travels through South America.\nA: How interesting! If I wrote one, it would be science fiction.\nB: What if we wrote one together?\nA: Intergalactic travels through South America. Perfect.",funFact:"-ir regular. 'Quería que escribiera la carta' (he wanted me to write the letter). Reported-speech past demands imperfect subjunctive."},
        {type:"teach",trg:"aprendiera",src:"I learned / I would learn (subj.)",pos:"noun",gender:null,phonetic:"ah-pren-DYE-ra",note:"From aprender. Preterite: aprendieron > aprendie- > aprendiera.",example:"A: Si aprendiera a cocinar, estaría muy contento.\nB: ¿No sabes cocinar nada?\nA: Solo huevos fritos.\nB: Si aprendieras recetas básicas, ya sería suficiente.\nA: Tienes razón. Empezaré mañana.",exampleSrc:"A: If I learned to cook, I would be very happy.\nB: Can you not cook anything?\nA: Only fried eggs.\nB: If you learned basic recipes, that would be enough.\nA: You are right. I will start tomorrow.",funFact:"Yo/él form. 'Era importante que aprendiera' (it was important that I learned). Past impersonal + subjunctive pattern."},
        {type:"teach",trg:"entendiera",src:"I understood / I would understand (subj.)",pos:"noun",gender:null,phonetic:"en-ten-DYE-ra",note:"From entender. Preterite: entendieron > entendie- > entendiera.",example:"A: Si entendiera mejor la gramática, no cometería tantos errores.\nB: No te preocupes. Los errores son parte del aprendizaje.\nA: Si todo el mundo entendiera eso, nadie tendría miedo de hablar.\nB: Exacto. Los errores son necesarios para aprender.\nA: Gracias. Eso me da más confianza.",exampleSrc:"A: If I understood grammar better, I would not make so many mistakes.\nB: Do not worry. Mistakes are part of learning.\nA: If everyone understood that, nobody would be afraid to speak.\nB: Exactly. Mistakes are necessary to learn.\nA: Thanks. That gives me more confidence.",funFact:"Yo/él form of entender. Note: stem-change e→ie stays ONLY in present. Imperfect subjunctive is regular: entendiera, not 'entiendiera.'"},
        {type:"mc",q:"'Si nosotros comiéramos más verduras' means:",opts:["We eat more vegetables","If we ate more vegetables","We will eat more vegetables","We used to eat more vegetables"],ans:"If we ate more vegetables",hint:"Si + imperfect subjunctive expresses a hypothetical condition."},
        {type:"fb",opts:["leyeran","leen","leerían","leerán"],hint:"From leer. The imperfect subjunctive of ellos form.",s:"Si los niños {1} más, sacarían mejores notas.",a:"leyeran"},
        {type:"mc",q:"Which pair of verbs shares the SAME imperfect subjunctive endings?",opts:["hablar and comer","hablar and vivir","comer and vivir","hablar and ser"],ans:"comer and vivir",hint:"-ER and -IR verbs have identical endings in this tense."},
        {type:"drag_fill",hint:"If-clause: imperfect subjunctive. Result clause: conditional.",s:"Si yo {1} más libros, {2} mejor.",blanks:{"1":"leyera","2":"escribiría"},pool:["leyera","escribiría","leo","escribo","leyendo"]},
        {type:"match",pairs:[
          {trg:"comiera",src:"I ate (subj.)"},
          {trg:"viviera",src:"I lived (subj.)"},
          {trg:"escribiera",src:"I wrote (subj.)"},
          {trg:"aprendiera",src:"I learned (subj.)"},
          {trg:"entendiera",src:"I understood (subj.)"}
        ]},
        {type:"mc",q:"To form 'viviera', you start from:",opts:["vivir (infinitive)","vivo (present yo)","viviré (future yo)","vivieron (preterite ellos)"],ans:"vivieron (preterite ellos)",hint:"Remove -ron from the ___ ___ form, then add -ra."},
        {type:"fb",opts:["entendieras","entiendes","entenderías","entendiste"],hint:"The tú form of the imperfect subjunctive of entender.",s:"Si tú {1} la situación, no estarías tan enfadado.",a:"entendieras"},
        {type:"mc",q:"'Si aprendiéramos chino, podríamos trabajar en Pekín.' The nosotros form has an accent because:",opts:["The stress must stay on the same syllable as other forms","All subjunctive forms have accents","It is irregular","Nosotros forms always have accents"],ans:"The stress must stay on the same syllable as other forms",hint:"The accent preserves the ___ pattern across all persons."}
  ]},
  {id:"esp25l3",title:"Si fuera, si tuviera...",icon:"🔮",xp:25,board:true,steps:[
        {type:"intro",title:"Si fuera, si tuviera...",desc:"Many common verbs have irregular preterite stems. The good news: the imperfect subjunctive endings are always the same. Just apply them to the irregular stem.",goals:["Form the imperfect subjunctive of key irregular verbs","Recognize irregular stems from the preterite","Use fuera, tuviera, hiciera, pudiera in context"]},
        {type:"tip",title:"Irregular Stems Come from the Preterite",text:"The imperfect subjunctive is NEVER irregular on its own. It always follows the preterite ellos form:\n\nser/ir > fueron > fue- > fuera\ntener > tuvieron > tuvie- > tuviera\nhacer > hicieron > hicie- > hiciera\npoder > pudieron > pudie- > pudiera\n\nSame -ra endings. Different stem.",icon:"🔑"},
        {type:"teach",trg:"fuera",src:"I were / I would be (subj.)",pos:"noun",gender:null,phonetic:"FWE-ra",note:"From ser AND ir. Both share the same form: fueron > fue- > fuera.",example:"A: Si fuera rico, compraría una casa en la montaña.\nB: ¿Solo una? Yo compraría tres.\nA: Si fueras millonario, ¿dejarías de trabajar?\nB: No. Si fuera millonario, trabajaría en lo que me gusta.\nA: Esa es la mejor respuesta.",exampleSrc:"A: If I were rich, I would buy a house in the mountains.\nB: Just one? I would buy three.\nA: If you were a millionaire, would you stop working?\nB: No. If I were a millionaire, I would work at what I enjoy.\nA: That is the best answer.",funFact:"Irregular. Same form for ser AND ir in imperfect subjunctive. 'Fuera' covers both. 'Si fuera rico' (if I were rich), 'si fuera al cine' (if I went to the movies). Context clarifies."},
        {type:"teach",trg:"tuviera",src:"I had / I would have (subj.)",pos:"noun",gender:null,phonetic:"too-BYE-ra",note:"From tener. Preterite: tuvieron > tuvie- > tuviera.",example:"A: Si tuviera más tiempo, aprendería a pintar.\nB: ¿Por qué no empiezas los fines de semana?\nA: Si tuviera los materiales, lo haría.\nB: En internet hay clases gratis.\nA: Si tuviéramos internet más rápido, podría ver los tutoriales.",exampleSrc:"A: If I had more time, I would learn to paint.\nB: Why don't you start on weekends?\nA: If I had the materials, I would do it.\nB: Online there are free classes.\nA: If we had faster internet, I could watch the tutorials.",funFact:"Irregular, tener. Stem: 'tuv-' + -iera. Very high frequency: 'si tuviera tiempo' (if I had time). Alt: tuviese."},
        {type:"teach",trg:"hiciera",src:"I did / I would do (subj.)",pos:"noun",gender:null,phonetic:"ee-SYE-ra",note:"From hacer. Preterite: hicieron > hicie- > hiciera.",example:"A: Si hiciera buen tiempo, iríamos a la playa.\nB: El pronóstico dice lluvia todo el fin de semana.\nA: Si no hiciera tanto frío, podríamos ir al parque.\nB: ¿Y si hiciéramos algo dentro de casa?\nA: Buena idea. Cocinemos algo rico.",exampleSrc:"A: If the weather were good, we would go to the beach.\nB: The forecast says rain all weekend.\nA: If it were not so cold, we could go to the park.\nB: What if we did something indoors?\nA: Good idea. Let us cook something nice.",funFact:"Irregular, hacer. Stem: 'hic-' + -iera. 'Si hiciera buen tiempo' (if the weather were good). Weather hypotheticals constantly."},
        {type:"teach",trg:"pudiera",src:"I could / I were able (subj.)",pos:"noun",gender:null,phonetic:"poo-DYE-ra",note:"From poder. Preterite: pudieron > pudie- > pudiera.",example:"A: Si pudiera elegir cualquier profesión, sería astronauta.\nB: ¿De verdad? Yo sería veterinario.\nA: Si pudiéramos viajar al espacio, ¿irías?\nB: Solo si pudiera llevar a mi perro.\nA: No creo que eso fuera posible.",exampleSrc:"A: If I could choose any profession, I would be an astronaut.\nB: Really? I would be a vet.\nA: If we could travel to space, would you go?\nB: Only if I could bring my dog.\nA: I do not think that would be possible.",funFact:"Irregular, poder. Stem: 'pud-' + -iera. 'Si pudiera volar' (if I could fly). Maps to English 'if I could' structure."},
        {type:"teach",trg:"dijera",src:"I said / I would say (subj.)",pos:"noun",gender:null,phonetic:"dee-HE-ra",note:"From decir. Preterite: dijeron > dije- > dijera. Note: j, not c.",example:"A: Si te dijera un secreto, ¿serías discreto?\nB: Por supuesto. Nunca se lo diría a nadie.\nA: Si alguien te dijera que es mentira, no le creas.\nB: ¿Es algo tan importante?\nA: Sí. Es muy importante.",exampleSrc:"A: If I told you a secret, would you be discreet?\nB: Of course. I would never tell anyone.\nA: If someone told you it is a lie, do not believe them.\nB: Is it something that important?\nA: Yes. It is very important.",funFact:"Irregular, decir. Stem: 'dij-' + -era (special rule: -era not -iera after 'j'). Same rule for traer → trajera, producir → produjera."},
        {type:"teach",trg:"supiera",src:"I knew / I would know (subj.)",pos:"noun",gender:null,phonetic:"soo-PYE-ra",note:"From saber. Preterite: supieron > supie- > supiera.",example:"A: Si supiera la respuesta, te la diría.\nB: Nadie la sabe. Es un misterio.\nA: Si alguien supiera la verdad, ¿la revelaría?\nB: Depende. Si yo supiera algo peligroso, tendría miedo.\nA: Por eso es mejor no saber algunas cosas.",exampleSrc:"A: If I knew the answer, I would tell you.\nB: Nobody knows it. It is a mystery.\nA: If someone knew the truth, would they reveal it?\nB: It depends. If I knew something dangerous, I would be afraid.\nA: That is why it is better not to know some things.",funFact:"Irregular, saber. Stem: 'sup-' + -iera. 'Si supiera...'; if I knew... Regret or hypothetical. Shared irregularity with preterite (supe, supiste)."},
        {type:"verb_table",title:"Key Irregular Imperfect Subjunctive Forms",note:"All use -ra endings. The stem is always from the preterite ellos form.",groups:[{label:"Stem from preterite",items:["ser/ir: fuera","tener: tuviera","hacer: hiciera"],rows:[]},{label:"More irregulars",items:["poder: pudiera","decir: dijera","saber: supiera"],rows:[]}],label:"Common irregulars"},
        {type:"mc",q:"The imperfect subjunctive of 'yo ser' is:",opts:["fuera","sería","era","sea"],ans:"fuera",hint:"From fueron, drop -ron, add -ra."},
        {type:"mc",q:"'Si tuviera dinero' means:",opts:["I have money","If I had money","I will have money","I had money yesterday"],ans:"If I had money",hint:"Si + imperfect subjunctive marks an unreal present condition."},
        {type:"fb",opts:["fuera","sería","era","fui"],hint:"The imperfect subjunctive of ser, used in a common expression.",s:"Si yo {1} tú, no haría eso.",a:"fuera"},
        {type:"fb",opts:["supiera","sabe","sabría","supo"],hint:"From saber. The imperfect subjunctive for an if-clause.",s:"Si ella {1} la verdad, nos la diría.",a:"supiera"},
        {type:"mc",q:"Why do ser and ir have the SAME imperfect subjunctive form?",opts:["It is a coincidence","All irregular verbs share forms","They share the same preterite form (fueron)","Only in the yo form"],ans:"They share the same preterite form (fueron)",hint:"The stem comes from the ___ ellos ___, which is identical for both verbs."},
        {type:"drag_fill",hint:"If-clause: imperfect subjunctive of poder. Result: conditional of viajar.",s:"Si {1} hacer cualquier cosa, {2} por todo el mundo.",blanks:{"1":"pudiera","2":"viajaría"},pool:["pudiera","viajaría","puedo","viajo","podría"]},
        {type:"match",pairs:[
          {trg:"fuera",src:"I were (subj.)"},
          {trg:"tuviera",src:"I had (subj.)"},
          {trg:"hiciera",src:"I did (subj.)"},
          {trg:"pudiera",src:"I could (subj.)"},
          {trg:"dijera",src:"I said (subj.)"},
          {trg:"supiera",src:"I knew (subj.)"}
        ]},
        {type:"mc",q:"Complete: 'Si él me lo _____, yo le ayudaría.' (decir)",opts:["diga","dice","diría","dijera"],ans:"dijera",hint:"The if-clause requires the imperfect subjunctive, not present or conditional."},
        {type:"fb",opts:["supiéramos","sabemos","sabríamos","supimos"],hint:"Nosotros form of the imperfect subjunctive of saber. Note the accent.",s:"Si nosotros {1} la verdad, no estaríamos tan preocupados.",a:"supiéramos"}
  ]},
  {id:"esp25l4",title:"Si tuviera dinero...",icon:"💭",xp:25,board:true,steps:[
        {type:"intro",title:"Si tuviera dinero...",desc:"The classic counterfactual pattern: Si + imperfect subjunctive + conditional. This is one of the most important structures in advanced Spanish.",goals:["Build complete counterfactual sentences","Distinguish real conditions (si + present) from unreal ones (si + imperfect subjunctive)","Use the pattern naturally in conversation"]},
        {type:"tip",title:"Real vs Unreal Conditions",text:"Spanish has two main conditional patterns:\n\nReal (likely or possible):\nSi tengo tiempo, voy al cine.\nIf I have time, I go to the movies.\n\nUnreal (hypothetical, unlikely):\nSi tuviera tiempo, iría al cine.\nIf I had time, I would go to the movies.\n\nThe difference: present indicative vs imperfect subjunctive in the if-clause.",icon:"📖"},
        {type:"teach",trg:"Si tuviera dinero, viajaría.",src:"If I had money, I would travel.",pos:"intj",gender:null,phonetic:"see too-BYE-ra dee-NE-ro, bya-ha-REE-a",note:"The classic pattern: si + imperfect subjunctive, + conditional.",example:"A: Si tuviera dinero, viajaría por toda Latinoamérica.\nB: ¿A qué país irías primero?\nA: A Colombia. Dicen que es increíble.\nB: Si yo tuviera vacaciones, te acompañaría.\nA: Algún día lo haremos. Solo necesitamos ahorrar.",exampleSrc:"A: If I had money, I would travel through all of Latin America.\nB: Which country would you go to first?\nA: To Colombia. They say it is incredible.\nB: If I had vacation, I would go with you.\nA: Someday we will do it. We just need to save.",funFact:"Second conditional: si + imperfect subjunctive, main conditional. Hypothetical present. 'Tuviera' can also be 'tuviese'; both forms are correct."},
        {type:"teach",trg:"Si pudiera, lo haría.",src:"If I could, I would do it.",pos:"intj",gender:null,phonetic:"see poo-DYE-ra, lo a-REE-a",note:"A very common expression. Short and versatile.",example:"A: ¿Por qué no vienes a la fiesta?\nB: Si pudiera, iría. Pero tengo que trabajar.\nA: ¡Qué pena! Si pudieras cambiar tu turno...\nB: Si pudiera cambiar mi turno, estaría allí sin duda.\nA: La próxima vez planificamos con más tiempo.",exampleSrc:"A: Why are you not coming to the party?\nB: If I could, I would go. But I have to work.\nA: What a shame! If you could switch your shift...\nB: If I could switch my shift, I would be there for sure.\nA: Next time we will plan with more time.",funFact:"Classic second conditional. The -iera ending on pudiera marks imperfect subjunctive of poder. Simple, high-frequency: Spanish conditional songs and movies love this phrase."},
        {type:"mc",q:"'Si lloviera, me quedaría en casa' is:",opts:["A hypothetical: it probably will not rain","A real condition about today","A past event: it rained","A future plan: it will rain"],ans:"A hypothetical: it probably will not rain",hint:"The imperfect subjunctive signals that the speaker considers ___ unlikely."},
        {type:"fb",opts:["tuviera","tengo","tendría","tuve"],hint:"The if-clause needs the imperfect subjunctive of tener.",s:"Si {1} más tiempo, estudiaría japonés.",a:"tuviera"},
        {type:"teach",trg:"Si fuera posible, cambiaría de trabajo.",src:"If it were possible, I would change jobs.",pos:"intj",gender:null,phonetic:"see FWE-ra po-SEE-ble",note:"Si fuera posible is a fixed expression for hypothetical possibilities.",example:"A: ¿Estás contento con tu trabajo?\nB: No mucho. Si fuera posible, cambiaría de trabajo.\nA: ¿Qué te lo impide?\nB: La situación económica. Si hubiera más ofertas, buscaría algo nuevo.\nA: Entiendo. Si yo estuviera en tu lugar, haría lo mismo.",exampleSrc:"A: Are you happy with your job?\nB: Not much. If it were possible, I would change jobs.\nA: What is stopping you?\nB: The economic situation. If there were more offers, I would look for something new.\nA: I understand. If I were in your place, I would do the same.",funFact:"'Fuera' covers ser AND ir in imperfect subjunctive. Context makes ser clear here ('if it were possible'). 'Cambiaría de trabajo' uses de, not el, after cambiar."},
        {type:"teach",trg:"Si estuviera en tu lugar",src:"If I were in your place",pos:"intj",gender:null,phonetic:"see es-too-BYE-ra en too loo-GAR",note:"A common empathy expression. Uses estuviera (imperfect subjunctive of estar).",example:"A: No sé qué hacer con mi relación.\nB: Si estuviera en tu lugar, hablaría con ella.\nA: ¿Y si no quisiera escucharme?\nB: Si no quisiera, al menos lo habrías intentado.\nA: Tienes razón. Hablaré con ella esta noche.",exampleSrc:"A: I do not know what to do about my relationship.\nB: If I were in your place, I would talk to her.\nA: What if she did not want to listen?\nB: If she did not want to, at least you would have tried.\nA: You are right. I will talk to her tonight.",funFact:"Formal hypothesis. Contrast with idiomatic 'yo en tu lugar' (elliptical, no verb). 'Si estuviera en tu lugar' is explicit and formal."},
        {type:"mc",q:"Which sentence is a REAL condition (not hypothetical)?",opts:["Si tuviera hambre, comería algo","Si tengo hambre, como algo","Si fuera rico, viajaría","Si pudiera, iría"],ans:"Si tengo hambre, como algo",hint:"Real conditions use the present indicative, not the imperfect subjunctive."},
        {type:"mc",q:"'Si yo fuera tú' translates to:",opts:["If I am you","When I was you","If I were you","I will be you"],ans:"If I were you",hint:"This common expression uses the unreal condition pattern."},
        {type:"fb",opts:["estuviera","está","estaría","estuvo"],hint:"Imperfect subjunctive of estar for a hypothetical presence.",s:"Si ella {1} aquí, nos ayudaría.",a:"estuviera"},
        {type:"drag_fill",hint:"If-clause: imperfect subjunctive. Result clause: conditional.",s:"Si yo {1} presidente, {2} la educación.",blanks:{"1":"fuera","2":"mejoraría"},pool:["fuera","mejoraría","soy","mejoro","sería"]},
        {type:"mc",q:"What is wrong with 'Si tendría dinero, viajaría'?",opts:["Nothing, it is correct","Viajaría should be viajara","Tendría should be tendrá","The conditional cannot be in the if-clause"],ans:"The conditional cannot be in the if-clause",hint:"A common error. The if-___ takes the subjunctive, never the ___."},
        {type:"fb",opts:["fuera","es","sería","será"],hint:"The imperfect subjunctive of ser for a hypothetical possibility.",s:"Si {1} posible, iríamos a la playa.",a:"fuera"},
        {type:"match",pairs:[
          {trg:"Si tengo tiempo, voy.",src:"Real: If I have time, I go."},
          {trg:"Si tuviera tiempo, iría.",src:"Unreal: If I had time, I would go."},
          {trg:"Si llueve, me quedo.",src:"Real: If it rains, I stay."},
          {trg:"Si lloviera, me quedaría.",src:"Unreal: If it rained, I would stay."}
        ]},
        {type:"mc",q:"You want to say something is unlikely but possible. You use:",opts:["Si + imperfect subjunctive + conditional","Si + present indicative + present","Si + future + conditional","Si + preterite + imperfect"],ans:"Si + imperfect subjunctive + conditional",hint:"This is the standard pattern for hypothetical or unlikely situations."},
        {type:"drag_fill",hint:"Hypothetical living situation. Subjunctive in if-clause, conditional in result.",s:"Si nosotros {1} en España, {2} español todos los días.",blanks:{"1":"viviéramos","2":"hablaríamos"},pool:["viviéramos","hablaríamos","vivimos","hablamos","viviendo"]},
        {type:"mc",q:"'Si pudiera volar, visitaría todos los países del mundo.' This sentence expresses:",opts:["A future plan","An impossible wish","A past regret","A real possibility"],ans:"An impossible wish",hint:"Humans cannot fly. The imperfect subjunctive marks this as ___."}
  ]},
  {id:"esp25l5",title:"Para que, como si...",icon:"🎯",xp:25,board:true,steps:[
        {type:"intro",title:"Para que, como si...",desc:"Beyond si clauses, the imperfect subjunctive appears after specific trigger expressions in past or hypothetical contexts. Master these to sound truly advanced.",goals:["Use para que + imperfect subjunctive","Use antes de que + imperfect subjunctive","Use como si + imperfect subjunctive","Use sin que + imperfect subjunctive"]},
        {type:"tip",title:"Triggers That Demand Subjunctive",text:"These expressions ALWAYS require subjunctive. In past or hypothetical contexts, they take the imperfect subjunctive:\n\npara que = so that, in order that\nantes de que = before\ncomo si = as if\nsin que = without (someone doing)\n\nPresent context > present subjunctive\nPast/hypothetical context > imperfect subjunctive",icon:"📖"},
        {type:"teach",trg:"para que pudiera",src:"so that (someone) could",pos:"verb",gender:null,phonetic:"PA-ra keh poo-DYE-ra",note:"Para que + imperfect subjunctive when the main verb is in the past.",example:"A: ¿Por qué le diste dinero?\nB: Se lo di para que pudiera comprar los libros.\nA: Eso fue muy generoso.\nB: Lo hice para que no tuviera que preocuparse.\nA: Ojalá más gente fuera así de solidaria.",exampleSrc:"A: Why did you give him money?\nB: I gave it to him so that he could buy the books.\nA: That was very generous.\nB: I did it so that he would not have to worry.\nA: I wish more people were that supportive.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"antes de que llegara",src:"before (someone) arrived",pos:"intj",gender:null,phonetic:"AN-tes deh keh yeh-GA-ra",note:"Antes de que always takes subjunctive. Past context: imperfect subjunctive.",example:"A: ¿Terminaste el informe?\nB: Sí, lo terminé antes de que llegara el jefe.\nA: Menos mal. Estaba muy nervioso.\nB: Yo también. Quería terminar antes de que empezara la reunión.\nA: Hiciste bien. El jefe quedó impresionado.",exampleSrc:"A: Did you finish the report?\nB: Yes, I finished it before the boss arrived.\nA: Thank goodness. He was very nervous.\nB: Me too. I wanted to finish before the meeting started.\nA: You did well. The boss was impressed.",funFact:"Subjunctive after 'antes de que' even in past reference. Imperfect subjunctive llegara harmonizes with past context. Never indicative after 'antes de que.'"},
        {type:"teach",trg:"como si fuera",src:"as if it were",pos:"intj",gender:null,phonetic:"KO-mo see FWE-ra",note:"Como si ALWAYS takes imperfect subjunctive, even in present contexts. It implies unreality.",example:"A: ¿Por qué habla como si fuera el jefe?\nB: Porque se cree muy importante.\nA: Actúa como si supiera todo.\nB: Exacto. Y trabaja como si no tuviera prisa nunca.\nA: Algún día tendrá que aceptar la realidad.",exampleSrc:"A: Why does he talk as if he were the boss?\nB: Because he thinks he is very important.\nA: He acts as if he knew everything.\nB: Exactly. And he works as if he were never in a hurry.\nA: Someday he will have to accept reality.",funFact:"'Como si' always takes imperfect or pluperfect subjunctive. 'Como si fuera experto' (as if he were an expert). Evokes English 'as if' followed by past."},
        {type:"teach",trg:"sin que supiera",src:"without (someone) knowing",pos:"intj",gender:null,phonetic:"seen keh soo-PYE-ra",note:"Sin que + subjunctive. Past context: imperfect subjunctive.",example:"A: ¿Cómo organizaste la fiesta sorpresa?\nB: Lo hice todo sin que mi esposa supiera nada.\nA: ¿Nadie se lo dijo?\nB: Invité a todos sin que ella se enterara.\nA: ¡Increíble! Debe de haber sido muy difícil.",exampleSrc:"A: How did you organize the surprise party?\nB: I did everything without my wife knowing anything.\nA: Nobody told her?\nB: I invited everyone without her finding out.\nA: Incredible! It must have been very difficult.",funFact:"'Sin que' always triggers subjunctive. 'Supiera' is imperfect subjunctive of saber with the irregular sup- stem."},
        {type:"mc",q:"'Como si fuera fácil' means:",opts:["As if it were easy","Because it is easy","When it was easy","Since it is easy"],ans:"As if it were easy",hint:"Como si always implies something is not actually the case."},
        {type:"mc",q:"'Antes de que' ALWAYS requires:",opts:["Indicative","Subjunctive","Conditional","Infinitive"],ans:"Subjunctive",hint:"This trigger has no exceptions. It refers to an event that has not yet occurred from the speaker's point of view, which determines the mood."},
        {type:"fb",opts:["antes de","después de","para","porque"],hint:"This expression means 'before' and always triggers subjunctive.",s:"Lo preparé todo {1} que ella llegara.",a:"antes de"},
        {type:"fb",opts:["fuera","es","sería","era"],hint:"Como si always takes the imperfect subjunctive, even about the present.",s:"Habla como si {1} un experto.",a:"fuera"},
        {type:"teach",trg:"a menos que viniera",src:"unless (someone) came",pos:"intj",gender:null,phonetic:"ah ME-nos keh bee-NYE-ra",note:"A menos que = unless. Always takes subjunctive.",example:"A: No iba a ir a la fiesta a menos que viniera mi amiga.\nB: ¿Y al final vino?\nA: Sí. No habría ido a menos que ella me acompañara.\nB: Es bueno tener amigos así.\nA: Sin ella, me habría quedado en casa.",exampleSrc:"A: I was not going to go to the party unless my friend came.\nB: And did she come in the end?\nA: Yes. I would not have gone unless she accompanied me.\nB: It is good to have friends like that.\nA: Without her, I would have stayed home.",funFact:"'A menos que' always subjunctive. 'Viniera' imperfect subjunctive of venir. Past-time version of 'a menos que venga' (unless he comes)."},
        {type:"mc",q:"Which trigger ALWAYS uses imperfect subjunctive, even in present tense contexts?",opts:["para que","antes de que","como si","sin que"],ans:"como si",hint:"This expression inherently implies unreality, so it is always imperfect subjunctive."},
        {type:"drag_fill",hint:"So that you could rest. Purpose + imperfect subjunctive.",s:"Lo hice {1} que tú {2} descansar.",blanks:{"1":"para","2":"pudieras"},pool:["para","pudieras","porque","puedes","pudiste"]},
        {type:"fb",opts:["viera","vio","vería","ve"],hint:"Without anyone seeing him. Sin que + imperfect subjunctive.",s:"Salió de casa sin que nadie lo {1}.",a:"viera"},
        {type:"match",pairs:[
          {trg:"para que pudiera",src:"so that he/she could"},
          {trg:"antes de que llegara",src:"before he/she arrived"},
          {trg:"como si fuera",src:"as if it were"},
          {trg:"sin que supiera",src:"without knowing"},
          {trg:"a menos que viniera",src:"unless he/she came"}
        ]},
        {type:"mc",q:"'Le escribí la carta para que _____ mis razones.' (entender, él)",opts:["entiende","entenderá","entendería","entendiera"],ans:"entendiera",hint:"Para que + past context = imperfect subjunctive."},
        {type:"drag_fill",hint:"He acted as if he did not know anything.",s:"Actuaba {1} si no {2} nada.",blanks:{"1":"como","2":"supiera"},pool:["como","supiera","porque","sabe","sabría"]},
        {type:"mc",q:"'Llamé antes de que cerraran la tienda' uses imperfect subjunctive because:",opts:["Antes de que always requires subjunctive, and the context is past","The store was already closed","The speaker is uncertain","It is a wish"],ans:"Antes de que always requires subjunctive, and the context is past",hint:"This trigger word never takes indicative. ___ ___ determines which ___."}
  ]},
  {id:"esp25l6",title:"Ojalá pudiera...",icon:"🌟",xp:25,board:true,steps:[
        {type:"intro",title:"Ojalá pudiera...",desc:"Ojalá is a beautiful word from Arabic (inshallah). With the imperfect subjunctive, it expresses wishes that are unlikely or impossible. With the present subjunctive, it expresses hopes that might still happen.",goals:["Distinguish ojalá + present subjunctive (possible) from ojalá + imperfect subjunctive (unlikely/impossible)","Express impossible wishes and deep longings","Use ojalá naturally in conversation"]},
        {type:"tip",title:"Ojalá: Hope vs Wish",text:"Ojalá changes meaning based on the subjunctive tense:\n\nOjalá llueva. = I hope it rains. (possible)\nOjalá lloviera. = I wish it would rain. (unlikely)\n\nOjalá venga. = I hope he comes. (might happen)\nOjalá viniera. = I wish he would come. (probably will not)\n\nPresent subjunctive = realistic hope\nImperfect subjunctive = unlikely wish or longing",icon:"💡"},
        {type:"teach",trg:"Ojalá pudiera",src:"I wish I could",pos:"intj",gender:null,phonetic:"oh-ha-LA poo-DYE-ra",note:"Ojalá + imperfect subjunctive for wishes unlikely to come true.",example:"A: Ojalá pudiera viajar más.\nB: ¿Qué te lo impide?\nA: El trabajo. Ojalá tuviera más vacaciones.\nB: Ojalá pudiéramos tomarnos un año libre.\nA: Eso sería un sueño. Ojalá fuera posible.",exampleSrc:"A: I wish I could travel more.\nB: What is stopping you?\nA: Work. I wish I had more vacation.\nB: I wish we could take a year off.\nA: That would be a dream. I wish it were possible.",funFact:"'Ojalá' + imperfect subjunctive = wish about the present (unrealistic). 'Ojalá pudiera'; I wish I could. Unreachable hope."},
        {type:"teach",trg:"Ojalá fuera más fácil",src:"I wish it were easier",pos:"intj",gender:null,phonetic:"oh-ha-LA FWE-ra mas FA-seel",note:"Expresses a wish about a current situation that cannot be changed.",example:"A: Aprender gramática es tan difícil.\nB: Ojalá fuera más fácil.\nA: Ojalá existiera una forma mágica de aprender.\nB: Ojalá pudiéramos aprender idiomas durmiendo.\nA: Bueno, al menos estamos practicando.",exampleSrc:"A: Learning grammar is so difficult.\nB: I wish it were easier.\nA: I wish there were a magical way to learn.\nB: I wish we could learn languages while sleeping.\nA: Well, at least we are practicing.",funFact:"'Fuera' here is clearly ser. 'I wish it were easier.' Unrealized wish about current state."},
        {type:"teach",trg:"Ojalá estuviera aquí",src:"I wish he/she were here",pos:"intj",gender:null,phonetic:"oh-ha-LA es-too-BYE-ra ah-KEE",note:"Used for wishes about people who are absent or situations that are impossible.",example:"A: Echo mucho de menos a mi abuela.\nB: Ojalá estuviera aquí. Ella siempre sabía qué decir.\nA: Ojalá pudiera escuchar su voz una vez más.\nB: Estoy seguro de que estaría muy orgullosa de ti.\nA: Gracias. Eso significa mucho para mí.",exampleSrc:"A: I miss my grandmother so much.\nB: I wish she were here. She always knew what to say.\nA: I wish I could hear her voice one more time.\nB: I am sure she would be very proud of you.\nA: Thank you. That means a lot to me.",funFact:"Estar imperfect subjunctive 'estuviera.' Wish about absence. 'Ojalá estuviera aquí'; I wish he/she were here. Classic longing phrase."},
        {type:"mc",q:"'Ojalá hiciera sol mañana' expresses:",opts:["An unlikely wish: the speaker doubts it","A realistic hope about tomorrow","Certainty that it will be sunny","A past event: it was sunny"],ans:"An unlikely wish: the speaker doubts it",hint:"Imperfect subjunctive with ojalá means the ___ thinks it is ___."},
        {type:"mc",q:"'Ojalá llueva mañana' vs 'Ojalá lloviera mañana'. The difference is:",opts:["No difference","Llueva = hope (possible), lloviera = wish (unlikely)","Llueva = past, lloviera = future","Llueva = formal, lloviera = informal"],ans:"Llueva = hope (possible), lloviera = wish (unlikely)",hint:"Present subjunctive for realistic ___s, imperfect subjunctive for ___ ___es."},
        {type:"fb",opts:["hubiera","hay","habrá","habría"],hint:"An impossible wish. There are always 24 hours. Use imperfect subjunctive.",s:"Ojalá {1} más horas en el día.",a:"hubiera"},
        {type:"teach",trg:"Ojalá no tuviera que trabajar",src:"I wish I did not have to work",pos:"intj",gender:null,phonetic:"oh-ha-LA no too-BYE-ra keh tra-ba-HAR",note:"Negative wishes. No + imperfect subjunctive after ojalá.",example:"A: Ojalá no tuviera que trabajar mañana.\nB: ¿No pediste el día libre?\nA: No. Ojalá pudiera, pero hay una reunión importante.\nB: Ojalá fueras tu propio jefe.\nA: Ojalá. Eso cambiaría todo.",exampleSrc:"A: I wish I did not have to work tomorrow.\nB: Did you not ask for the day off?\nA: No. I wish I could, but there is an important meeting.\nB: I wish you were your own boss.\nA: I wish. That would change everything.",funFact:"Tener que + infinitive in subjunctive: 'no tuviera que trabajar.' Subjunctive expresses hypothetical non-work. Strong longing register."},
        {type:"teach",trg:"Ojalá",src:"I wish / I hope (from Arabic)",pos:"noun",gender:null,phonetic:"oh-ha-LA",note:"From Arabic 'inshallah' (God willing). One of many Arabic loanwords in Spanish.",example:"A: ¿Sabes de dónde viene la palabra ojalá?\nB: Creo que del árabe.\nA: Sí, de 'inshallah', que significa 'si Dios quiere'.\nB: ¡Qué interesante! Ojalá supiera más sobre la historia del español.\nA: Hay muchas palabras del árabe en español: almohada, alfombra, azúcar...",exampleSrc:"A: Do you know where the word ojalá comes from?\nB: I think from Arabic.\nA: Yes, from 'inshallah', which means 'God willing'.\nB: How interesting! I wish I knew more about the history of Spanish.\nA: There are many Arabic words in Spanish: almohada, alfombra, azúcar...",funFact:"Spanish's most beloved subjunctive trigger. From Arabic 'wa-sha-Allah' (may God will it). Used with present subjunctive for wishes about future, imperfect subjunctive for wishes about present/hypothetical."},
        {type:"mc",q:"The word ojalá comes from:",opts:["Latin","Greek","Arabic","French"],ans:"Arabic",hint:"It evolved from a phrase meaning 'God willing'."},
        {type:"fb",opts:["pudiera","puedo","podría","pueda"],hint:"An impossible wish. Humans cannot fly. Imperfect subjunctive.",s:"Ojalá {1} volar como los pájaros.",a:"pudiera"},
        {type:"mc",q:"Which sentence expresses a POSSIBLE hope?",opts:["Ojalá fuera millonario","Ojalá aprobara el examen","Ojalá pudiera volar","Ojalá apruebe el examen"],ans:"Ojalá apruebe el examen",hint:"Present subjunctive (___) signals the speaker thinks it is still possible."},
        {type:"drag_fill",hint:"An unlikely wish about having time. Imperfect subjunctive + infinitive.",s:"Ojalá {1} más tiempo para {2} con mi familia.",blanks:{"1":"tuviera","2":"estar"},pool:["tuviera","estar","tengo","estoy","tendría"]},
        {type:"match",pairs:[
          {trg:"Ojalá llueva",src:"I hope it rains (possible)"},
          {trg:"Ojalá lloviera",src:"I wish it rained (unlikely)"},
          {trg:"Ojalá venga",src:"I hope he comes (possible)"},
          {trg:"Ojalá viniera",src:"I wish he came (unlikely)"},
          {trg:"Ojalá pudiera",src:"I wish I could (impossible)"}
        ]},
        {type:"fb",opts:["estuviera","está","estaría","esté"],hint:"Wishing someone absent were present. Imperfect subjunctive.",s:"Ojalá {1} aquí para verte.",a:"estuviera"},
        {type:"mc",q:"You failed an exam and say 'Ojalá hubiera estudiado más.' This uses:",opts:["Pluperfect subjunctive (impossible past)","Imperfect subjunctive (unlikely present)","Present subjunctive (realistic)","Conditional (polite request)"],ans:"Pluperfect subjunctive (impossible past)",hint:"Hubiera + ___ participle expresses a wish about an unchangeable ___."},
        {type:"mc",q:"Your friend is nervous about a job interview tomorrow. You say:",opts:["Ojalá le fuera bien","Ojalá le vaya bien","Ojalá le iría bien","Ojalá le fue bien"],ans:"Ojalá le vaya bien",hint:"The interview has not happened yet and could still go well. Use present subjunctive for realistic hopes."}
  ]},
  {id:"esp25l7",title:"Si hubiera sabido...",icon:"⏳",xp:25,board:true,steps:[
        {type:"intro",title:"Si hubiera sabido...",desc:"Now we combine everything: real scenarios using counterfactuals, regrets about the past, and alternative histories. This lesson focuses on using imperfect subjunctive to discuss what could have been different.",goals:["Express regrets and missed opportunities","Discuss alternative outcomes for past situations","Combine imperfect subjunctive with other tenses naturally"]},
        {type:"tip",title:"Counterfactuals in Real Life",text:"Counterfactuals are everywhere in daily conversation:\n\nSi hubiera sabido... = If I had known...\nSi no fuera por ti... = If it were not for you...\nSi pudiera volver atrás... = If I could go back...\n\nThey express regrets, gratitude, longing, and hypothetical reasoning. Mastering them makes your Spanish deeply expressive.",icon:"📖"},
        {type:"teach",trg:"Si hubiera sabido",src:"If I had known",pos:"intj",gender:null,phonetic:"see oo-BYE-ra sa-BEE-do",note:"Si + pluperfect subjunctive (hubiera + participle) for past counterfactuals.",example:"A: Si hubiera sabido que llovería, habría traído un paraguas.\nB: Yo tampoco lo sabía. Ahora estamos empapados.\nA: Si hubiéramos visto el pronóstico del tiempo...\nB: Si hubiera sabido, habría cancelado el picnic.\nA: La próxima vez, miraremos el tiempo antes de salir.",exampleSrc:"A: If I had known it would rain, I would have brought an umbrella.\nB: I did not know either. Now we are soaked.\nA: If we had seen the weather forecast...\nB: If I had known, I would have canceled the picnic.\nA: Next time, we will look at the weather before going out.",funFact:"Third conditional: si + pluperfect subjunctive. Contrary-to-past-fact. 'Si hubiera sabido'; if only I had known (but I didn't)."},
        {type:"teach",trg:"Si no fuera por ti",src:"If it were not for you",pos:"intj",gender:null,phonetic:"see no FWE-ra por tee",note:"A fixed expression of gratitude. Si no fuera por + person/thing.",example:"A: Aprobé el examen gracias a tu ayuda.\nB: Tú hiciste todo el trabajo.\nA: Si no fuera por ti, no habría entendido nada.\nB: Si no fuera por tu esfuerzo, no habrías aprobado.\nA: Somos un buen equipo.",exampleSrc:"A: I passed the exam thanks to your help.\nB: You did all the work.\nA: If it were not for you, I would not have understood anything.\nB: If it were not for your effort, you would not have passed.\nA: We are a good team.",funFact:"Set phrase. 'If it weren't for you.' Can continue: 'si no fuera por ti, no estaría aquí.' Expresses gratitude or consequence-avoidance."},
        {type:"teach",trg:"Si pudiera volver atrás",src:"If I could go back",pos:"intj",gender:null,phonetic:"see poo-DYE-ra bol-VER ah-TRAS",note:"Expresses regret about past choices. Common in reflective conversations.",example:"A: Si pudiera volver atrás, estudiaría una carrera diferente.\nB: ¿Cuál elegirías?\nA: Medicina. Siempre me interesó.\nB: Si yo pudiera volver atrás, viviría en otro país.\nA: Nunca es tarde. La vida es muy larga.",exampleSrc:"A: If I could go back, I would study a different degree.\nB: Which one would you choose?\nA: Medicine. It always interested me.\nB: If I could go back, I would live in another country.\nA: It is never too late. Life is very long.",funFact:"Hypothetical of poder. 'Volver atrás' (go back in time). Romantic or regretful register."},
        {type:"mc",q:"'Si hubiera estudiado más, habría aprobado' means:",opts:["If I had studied more, I would have passed","If I studied more, I would pass","If I study more, I pass","I studied more and I passed"],ans:"If I had studied more, I would have passed",hint:"Hubiera + participle refers to a past that did not happen."},
        {type:"fb",opts:["hubiera","habría","había","haya"],hint:"The si clause about a past that did not happen requires the pluperfect subjunctive form of haber.",s:"Si {1} sabido la verdad, no habría confiado en él.",a:"hubiera"},
        {type:"teach",trg:"Me gustaría que fuera diferente",src:"I would like it to be different",pos:"intj",gender:null,phonetic:"meh goos-ta-REE-a keh FWE-ra dee-feh-REN-teh",note:"Me gustaría que + imperfect subjunctive for wishes about current situations.",example:"A: La situación en el trabajo es complicada.\nB: Me gustaría que fuera diferente.\nA: A mí también. Si pudiéramos cambiar las reglas...\nB: Si el jefe escuchara nuestras ideas, todo mejoraría.\nA: Ojalá nos escuchara algún día.",exampleSrc:"A: The situation at work is complicated.\nB: I would like it to be different.\nA: Me too. If we could change the rules...\nB: If the boss listened to our ideas, everything would improve.\nA: I wish he would listen to us someday.",funFact:"Conditional wish clause requiring subjunctive. 'Fuera' for the hypothetical state. Common therapy-speak: 'quisiera que fuera diferente.'"},
        {type:"teach",trg:"Habría sido mejor si",src:"It would have been better if",pos:"intj",gender:null,phonetic:"ah-BREE-a SEE-do meh-HOR see",note:"Conditional perfect + si + pluperfect subjunctive for past regrets.",example:"A: Habría sido mejor si hubiéramos empezado antes.\nB: Sí, ahora no tendríamos tanta prisa.\nA: Habría sido mejor si hubiera pedido ayuda.\nB: No te culpes. Todos cometemos errores.\nA: La próxima vez planificaré mejor.",exampleSrc:"A: It would have been better if we had started earlier.\nB: Yes, now we would not be in such a hurry.\nA: It would have been better if I had asked for help.\nB: Do not blame yourself. We all make mistakes.\nA: Next time I will plan better.",funFact:"Past conditional (habría sido) + third-conditional si-clause. Typical regret structure. 'Habría sido mejor si hubiera...'; would have been better if I had..."},
        {type:"mc",q:"'Si no fuera por el café, no podría funcionar por las mañanas' expresses:",opts:["A fact about coffee","A hypothetical: without coffee, mornings would be impossible","A past event","A future plan to drink coffee"],ans:"A hypothetical: without coffee, mornings would be impossible",hint:"Si no fuera por marks something as essential by imagining life ___ it."},
        {type:"fb",opts:["pudiera","puedo","podría","pude"],hint:"If I could go back. The if-clause uses imperfect subjunctive.",s:"Si {1} volver atrás, elegiría otra carrera.",a:"pudiera"},
        {type:"drag_fill",hint:"If it were not for your help, I would not have finished.",s:"Si no {1} por tu ayuda, no habría {2} el proyecto.",blanks:{"1":"fuera","2":"terminado"},pool:["fuera","terminado","es","terminar","sería"]},
        {type:"mc",q:"Which sentence expresses a past regret?",opts:["Si tuviera dinero, viajaría","Si tengo dinero, viajo","Si hubiera tenido dinero, habría viajado","Si fuera rico, viajaría"],ans:"Si hubiera tenido dinero, habría viajado",hint:"Past regrets use the pluperfect subjunctive (___ + past participle)."},
        {type:"fb",opts:["hubiera dicho","dije","diría","dijera"],hint:"Past counterfactual: would have been better if (someone) had told the truth.",s:"Habría sido mejor si {1} la verdad desde el principio.",a:"hubiera dicho"},
        {type:"match",pairs:[
          {trg:"Si hubiera sabido",src:"If I had known"},
          {trg:"Si no fuera por ti",src:"If it were not for you"},
          {trg:"Si pudiera volver atrás",src:"If I could go back"},
          {trg:"Me gustaría que fuera",src:"I would like it to be"},
          {trg:"Habría sido mejor si",src:"It would have been better if"}
        ]},
        {type:"mc",q:"A friend helped you get a job. You say gratefully:",opts:["Si fuera por ti, no tendría trabajo","Si no sería por ti, no trabajo","Si hubiera sido por ti, trabajo","Si no fuera por ti, no tendría este trabajo"],ans:"Si no fuera por ti, no tendría este trabajo",hint:"Express that without your friend, you would not have the job."},
        {type:"drag_fill",hint:"If I had paid more attention, I would not have made that mistake.",s:"Si {1} más atención, no {2} cometido ese error.",blanks:{"1":"hubiera prestado","2":"habría"},pool:["hubiera prestado","habría","presto","hay","hubieron"]},
        {type:"mc",q:"'Si pudiera cambiar algo de mi pasado, sería más amable con la gente.' The speaker:",opts:["Regrets not being kinder","Plans to change in the future","Is very kind to everyone","Asks for advice"],ans:"Regrets not being kinder",hint:"The counterfactual structure implies something was different in the past."}
  ]},
  {id:"esp25l8",title:"Repaso: Subjuntivo Imperfecto",icon:"🏆",xp:30,board:true,steps:[
        {type:"intro",title:"Repaso: Subjuntivo Imperfecto",desc:"Time to bring it all together. This review covers formation, triggers, counterfactuals, ojalá, and real-life applications of the imperfect subjunctive.",goals:["Demonstrate mastery of imperfect subjunctive formation","Use all trigger patterns confidently","Build complex counterfactual sentences from scratch"]},
        {type:"mc",q:"To form the imperfect subjunctive of ANY verb, you start from:",opts:["The preterite ellos form","The present yo form","The infinitive","The future stem"],ans:"The preterite ellos form",hint:"This rule works for all verbs, regular and irregular."},
        {type:"mc",q:"The imperfect subjunctive of 'ellos tener' is:",opts:["tienen","tuvieran","tuvieron","tenían"],ans:"tuvieran",hint:"From tuvieron, drop -ron, add -ran."},
        {type:"fb",opts:["fuera","soy","sería","era"],hint:"If I were braver. The if-clause takes imperfect subjunctive of ser.",s:"Si {1} más valiente, hablaría en público.",a:"fuera"},
        {type:"mc",q:"Which sentence is grammatically CORRECT?",opts:["Si tendría tiempo, iría","Si tenía tiempo, iría","Si tuviera tiempo, iría","Si tendré tiempo, iré"],ans:"Si tuviera tiempo, iría",hint:"The if-clause takes imperfect subjunctive, not conditional or imperfect indicative."},
        {type:"fb",opts:["hubiera","hay","habrá","habría"],hint:"An impossible wish about the world. Imperfect subjunctive after ojalá.",s:"Ojalá {1} un mundo sin guerras.",a:"hubiera"},
        {type:"drag_fill",hint:"He talks as if he knew everything. Como si + imperfect subjunctive.",s:"Habla {1} si {2} todo sobre el tema.",blanks:{"1":"como","2":"supiera"},pool:["como","supiera","porque","sabe","sabiendo"]},
        {type:"mc",q:"'Como si' is special because it ALWAYS takes:",opts:["Present indicative mood","Present subjunctive form","Conditional tense","Imperfect subjunctive"],ans:"Imperfect subjunctive",hint:"Even when the main clause is in the present, como si demands this form."},
        {type:"fb",opts:["tuviera","tiene","tendría","tenga"],hint:"So that she would not have to worry. Past context: imperfect subjunctive.",s:"Lo hice para que ella no {1} que preocuparse.",a:"tuviera"},
        {type:"drag_fill",hint:"If I were you, I would not do that. Classic counterfactual advice.",s:"Si yo {1} tú, no {2} eso.",blanks:{"1":"fuera","2":"haría"},pool:["fuera","haría","soy","hago","siendo"]},
        {type:"mc",q:"'Ojalá lloviera' vs 'Ojalá llueva'. Which expresses doubt?",opts:["Ojalá lloviera expresses doubt, llueva expresses hope","Both express the same thing","Ojalá llueva expresses doubt","Neither expresses doubt"],ans:"Ojalá lloviera expresses doubt, llueva expresses hope",hint:"Imperfect subjunctive signals the speaker thinks rain is unlikely."},
        {type:"fb",opts:["hubiera","habría","había","he"],hint:"Past counterfactual: the si clause needs the pluperfect subjunctive of haber (yo form).",s:"Si {1} sabido antes, te habría avisado.",a:"hubiera"},
        {type:"match",pairs:[
          {trg:"Si hablara",src:"If I spoke (unlikely)"},
          {trg:"Si hubiera hablado",src:"If I had spoken (past)"},
          {trg:"Ojalá hablara",src:"I wish I spoke"},
          {trg:"Como si hablara",src:"As if I spoke"},
          {trg:"Para que hablara",src:"So that I spoke"}
        ,{trg:"estudiara",src:"I studied / I would study (subj.)"}]},
        {type:"mc",q:"Your friend says: 'Si no fuera por mi familia, estaría perdido.' He feels:",opts:["Angry at his family","Grateful for his family","Indifferent about his family","Sad about losing his family"],ans:"Grateful for his family",hint:"By imagining life without them, he highlights how important they are."},
        {type:"drag_fill",hint:"If I lived in Spain, I would eat tapas every day.",s:"Si {1} en España, {2} tapas todos los días.",blanks:{"1":"viviera","2":"comería"},pool:["viviera","comería","vivo","como","viviendo"]},
        {type:"fb",opts:["notara","notó","notaría","nota"],hint:"He left without anyone noticing. Sin que + imperfect subjunctive.",s:"Salió sin que nadie lo {1}.",a:"notara"},
        {type:"mc",q:"Which is a correct past counterfactual?",opts:["Si tuviera dinero, viajé por ahí","Si tengo dinero, viajo a Europa","Si hubiera tenido dinero, habría viajado","Si tendría dinero, viajaría contigo"],ans:"Si hubiera tenido dinero, habría viajado",hint:"Past counterfactuals: si + pluperfect subjunctive + conditional perfect."},
        {type:"drag_fill",hint:"I wish there were more people like you in the world.",s:"Ojalá {1} más personas {2} tú en el mundo.",blanks:{"1":"hubiera","2":"como"},pool:["hubiera","como","hay","así","habría"]},
        {type:"mc",q:"You want to express that learning Spanish is hard but you wish it were easier. You say:",opts:["Ojalá es más fácil así","Ojalá sea más fácil mañana","Ojalá será más fácil pronto","Ojalá fuera más fácil"],ans:"Ojalá fuera más fácil",hint:"You know it is not easy and it will not change. Use imperfect subjunctive for this unlikely wish."}
  ]}
]};
